from dataclasses import dataclass
from datetime import date
from enum import Enum

class ModelLifecycleStage(str, Enum):
    CURRENT      = "current"      # recommended; all new integrations
    SUPPORTED    = "supported"    # production-eligible; no new features
    MAINTENANCE  = "maintenance"  # existing only; critical patches; migrate within 12mo
    DEPRECATED   = "deprecated"   # no patches; migration required immediately

@dataclass
class ModelVersionPolicy:
    model_id: str
    family: str                  # e.g. "claude-3-5-sonnet", "claude-3-opus"
    stage: ModelLifecycleStage
    eligible_for_new_integrations: bool
    security_patch_commitment: str  # "active", "critical_only", "none"
    eol_date: date | None           # None if not yet announced
    migration_target: str | None    # model_id to migrate to; None if CURRENT

    def requires_migration_plan(self) -> bool:
        return self.stage in (
            ModelLifecycleStage.MAINTENANCE,
            ModelLifecycleStage.DEPRECATED,
        )

    def blocks_new_integrations(self) -> bool:
        return self.stage in (
            ModelLifecycleStage.MAINTENANCE,
            ModelLifecycleStage.DEPRECATED,
        )

    def sla_for_migration(self) -> str:
        if self.stage == ModelLifecycleStage.DEPRECATED:
            return "immediate: migrate before EOL date"
        if self.stage == ModelLifecycleStage.MAINTENANCE:
            return "12 months from maintenance entry date"
        return "no migration required"

from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class MatrixChangeType(str, Enum):
    NEW_VERSION        = "new_version"        # new model version added to matrix
    STAGE_TRANSITION   = "stage_transition"   # version moved to new lifecycle stage
    EOL_ANNOUNCED      = "eol_announced"      # EOL date set for a version
    EOL_EXTENDED       = "eol_extended"       # EOL date moved later
    VERSION_REMOVED    = "version_removed"    # version removed (post-EOL)

@dataclass
class MatrixChangeRecord:
    change_type: MatrixChangeType
    model_id: str
    from_stage: str | None
    to_stage: str | None
    effective_date: date
    notice_days: int                # days advance notice given
    affected_services: list[str] = field(default_factory=list)
    migration_deadline: date | None = None

    def requires_team_notification(self) -> bool:
        return self.change_type in (
            MatrixChangeType.STAGE_TRANSITION,
            MatrixChangeType.EOL_ANNOUNCED,
        )

    def requires_migration_ticket(self) -> bool:
        return (
            self.change_type == MatrixChangeType.STAGE_TRANSITION
            and self.to_stage in ("maintenance", "deprecated")
        )

    def notification_message(self) -> str:
        if self.change_type == MatrixChangeType.EOL_ANNOUNCED:
            return (
                f"NOTICE: {self.model_id} has an announced EOL date of "
                f"{self.effective_date}. Services using this version must "
                f"complete migration by {self.migration_deadline}. "
                f"Affected: {', '.join(self.affected_services)}."
            )
        if self.change_type == MatrixChangeType.STAGE_TRANSITION:
            return (
                f"NOTICE: {self.model_id} transitions from {self.from_stage} "
                f"to {self.to_stage} on {self.effective_date}. "
                f"New integrations on this version are no longer permitted. "
                f"Existing integrations must migrate by {self.migration_deadline}."
            )
        return f"Matrix updated: {self.change_type.value} for {self.model_id}."

from dataclasses import dataclass
from datetime import date, timedelta

@dataclass
class MaintenanceMigrationPlan:
    service_name: str
    current_model_id: str
    target_model_id: str
    maintenance_entry_date: date
    migration_deadline: date        # maintenance_entry_date + 12 months

    def months_remaining(self, today: date) -> float:
        remaining = (self.migration_deadline - today).days
        return max(0.0, remaining / 30.44)

    def urgency(self, today: date) -> str:
        months = self.months_remaining(today)
        if months < 1:
            return "CRITICAL: migration deadline within 1 month"
        if months < 3:
            return "HIGH: start migration sprint immediately"
        if months < 6:
            return "MEDIUM: include in next quarterly planning"
        return "LOW: schedule in standard upgrade cadence"

    def migration_sprint_start(self) -> date:
        """
        Returns the latest date to START migration (allowing 90d for the work).
        """
        return self.migration_deadline - timedelta(days=90)

    def is_overdue_to_start(self, today: date) -> bool:
        return today > self.migration_sprint_start()

from dataclasses import dataclass
from enum import Enum

class ComplianceAction(str, Enum):
    ALLOW    = "allow"
    WARN     = "warn"     # allowed but flagged for review
    BLOCK    = "block"    # must not deploy to production

@dataclass
class ModelComplianceCheck:
    model_id: str
    matrix: dict   # {model_id: ModelVersionPolicy}

    def check(self) -> tuple[ComplianceAction, str]:
        policy = self.matrix.get(self.model_id)
        if policy is None:
            return (
                ComplianceAction.BLOCK,
                f"{self.model_id} is not in the approved model version matrix. "
                f"Use only versions listed in the matrix."
            )
        stage = policy.stage.value
        if stage == "deprecated":
            return (
                ComplianceAction.BLOCK,
                f"{self.model_id} is DEPRECATED. Immediate migration required. "
                f"Target: {policy.migration_target}."
            )
        if stage == "maintenance":
            return (
                ComplianceAction.WARN,
                f"{self.model_id} is in MAINTENANCE. No new integrations permitted. "
                f"Existing integrations must migrate to {policy.migration_target} "
                f"within the 12-month window."
            )
        if stage == "supported":
            return (
                ComplianceAction.WARN,
                f"{self.model_id} is SUPPORTED (not CURRENT). Acceptable for "
                f"existing integrations; consider upgrading to CURRENT version "
                f"at next maintenance window."
            )
        return (
            ComplianceAction.ALLOW,
            f"{self.model_id} is CURRENT. No compliance issues."
        )

    def blocks_deploy(self) -> bool:
        action, _ = self.check()
        return action == ComplianceAction.BLOCK

from dataclasses import dataclass, field
from datetime import date

@dataclass
class ServiceModelPosition:
    service_name: str
    model_id: str
    stage: str            # from approved matrix
    migration_deadline: date | None

@dataclass
class OrganisationModelInventory:
    services: list[ServiceModelPosition] = field(default_factory=list)
    as_of: date = field(default_factory=date.today)

    def by_stage(self, stage: str) -> list[ServiceModelPosition]:
        return [s for s in self.services if s.stage == stage]

    def deprecated_services(self) -> list[ServiceModelPosition]:
        return self.by_stage("deprecated")

    def at_risk_services(self, today: date, days_threshold: int = 60) -> list[ServiceModelPosition]:
        """
        Services whose migration deadline is within `days_threshold` days.
        """
        at_risk = []
        for s in self.services:
            if s.migration_deadline is None:
                continue
            days_remaining = (s.migration_deadline - today).days
            if 0 < days_remaining <= days_threshold:
                at_risk.append(s)
        return at_risk

    def compliance_summary(self, today: date) -> dict:
        total = len(self.services)
        return {
            "total_services": total,
            "current_count": len(self.by_stage("current")),
            "supported_count": len(self.by_stage("supported")),
            "maintenance_count": len(self.by_stage("maintenance")),
            "deprecated_count": len(self.deprecated_services()),
            "at_risk_60d": len(self.at_risk_services(today, 60)),
            "compliance_rate": (
                (total - len(self.deprecated_services())) / total
                if total > 0 else 1.0
            ),
        }
